function registerSuggest(server, http) {
  server.registerTool("legifrance_suggest", {
    title: "Autocomplete / suggestions L\xE9gifrance",
    description: "Autocomplete cross-fond. Saisissez un d\xE9but de texte (titre, mot-cl\xE9) et obtenez des suggestions structur\xE9es (textes, sections, articles) avec leurs identifiants. Utile pour r\xE9soudre un nom usuel en LEGITEXT/JURITEXT/etc. avant un appel `get_*`.",
    inputSchema: {
      query: external_exports.string().min(2).describe("Texte \xE0 autocompl\xE9ter (\u2265 2 caract\xE8res)."),
      supplies: external_exports.array(external_exports.enum(SUGGEST_SUPPLIES)).default(["ALL"]).describe("Fonds \xE0 interroger pour les suggestions.")
    }
  }, async (args) => {
    const body = {
      searchText: args.query,
      supplies: args.supplies,
      documentsDits: false
    };
    const raw = await http.post("/suggest", body);
    const parsed = SuggestResponseSchema.safeParse(raw);
    if (!parsed.success) {
      log.warn("suggest: response shape unexpected", { issues: parsed.error.issues.slice(0, 3) });
      return {
        isError: true,
        content: [{ type: "text", text: `R\xE9ponse L\xE9gifrance inattendue : ${parsed.error.message.slice(0, 300)}` }]
      };
    }
    const data = parsed.data;
    const lines = [];
    const results = data.results ?? [];
    if (Array.isArray(results)) {
      lines.push(`**${results.length} suggestion(s)** pour "${args.query}" :`);
      lines.push("");
      if (results.length === 0) {
        lines.push("_(aucune suggestion)_");
      } else {
        for (const value of results.slice(0, 15)) {
          const label = value.label ?? "(sans titre)";
          const meta3 = [value.nature, value.origin, normalizeLegiDate(value.dateVersion)].filter(Boolean).join(" \xB7 ");
          lines.push(`- **${label}** ${meta3 ? `_(${meta3})_` : ""}`);
          if (value.id)
            lines.push(`  \`${value.id}\``);
        }
      }
    } else {
      lines.push(`**${data.totalResultNumber ?? 0} suggestion(s)** pour "${args.query}" :`);
      lines.push("");
      let totalShown = 0;
      for (const [supply, items] of Object.entries(results)) {
        const entries = Object.entries(items);
        if (entries.length === 0)
          continue;
        lines.push(`### ${supply}`);
        for (const [id, value] of entries.slice(0, 5)) {
          const label = value.label ?? "(sans titre)";
          const meta3 = [value.nature, normalizeLegiDate(value.dateVersion)].filter(Boolean).join(" \xB7 ");
          lines.push(`- **${label}** ${meta3 ? `_(${meta3})_` : ""}`);
          lines.push(`  \`${id}\``);
          totalShown += 1;
        }
        lines.push("");
      }
      if (totalShown === 0) {
        lines.push("_(aucune suggestion)_");
      }
    }
    return { content: [{ type: "text", text: lines.join("\n") }] };
  });
}

